  position: fixed;
  left: 0;
  top: 0;
  width: 100%;
  height: 100%;
  padding-top: 120rpx;
  box-sizing: border-box;
  overflow: scroll;
}
.top {
  position: fixed;
  justify-content: space-around;
  height: 120rpx;
  left: 0;
  top: 0;
  width: 100%;
  padding: 0 54rpx;
  box-sizing: border-box;
  div {
    height: 60rpx;
    box-sizing: border-box;
    color: #fff;
    font-size: 36rpx;
  }
  .selected {
    color: #7efce4;
    border-bottom: 4rpx solid #7efce4;
  }
}

.bigMiddle {
  height: 100%;
  overflow: scroll;
  padding-bottom: 120rpx;
  box-sizing: border-box;
  .bigRankList {
    display: flex;
    justify-content: center;
    align-items: center;
    .rankList {
      display: flex;
      align-items: center;
      width: 708rpx;
      height: 156rpx;
      padding-bottom: 10rpx;
      box-sizing: border-box;
      background-size: 100%;
      background-repeat: no-repeat;
      background-image: url("data:image/png;base64,");
      .rank {
        width: 140rpx;
        display: flex;
        justify-content: center;
        align-items: center;
        padding-left: 20rpx;
        box-sizing: border-box;
        div {
          width: 60rpx;
          height: 73rpx;
          transform: scale(0.66);
        }
        span {
          color: white;
        }
      }
      .headImg {
        margin-right: 30rpx;
        img {
          width: 100rpx;
          height: 100rpx;
          border-radius: 50%;
          vertical-align: middle;
        }
      }
      .u-info {
        display: flex;
        justify-content: center;
        align-items: flex-start;
        flex-direction: column;
        font-weight: bold;
        .ninckName {
          width: 200rpx;
          font-size: 28rpx;
          color: #fff;
          overflow: hidden;
          text-overflow: ellipsis;
          white-space: nowrap;
