          margin-bottom: 30rpx;
        }
        .place {
          font-size: 24rpx;
          color: #a397fd;
          line-height: 1;
        }
      }

      .paraghImg {
        display: flex;
        align-items: center;
        justify-content: center;
        height: 100rpx;
        height: 100rpx;
        img {
          width: 100rpx;
          height: 100rpx;
          //margin-left: 145rpx;
        }
      }
      .paraghStar {
        width: 180rpx;
        margin-left: 10rpx;
        .star {
          height: 40rpx;
          img {
            width: 32rpx;
            height: 32rpx;
          }
          span {
            color: #fff;
            font-size: 25rpx;
