          }
        }
        .paraghName {
          color: white;
          font-size: 22rpx;
          padding-top: 5rpx;
          margin-bottom: 10rpx;
        }
      }
    }
    .big {
      height: 184rpx;
      background-size: 708rpx 184rpx;
    }
  }
}
.bigBottom {
  position: fixed;
  display: flex;
  align-items: center;
  height: 82rpx;
  width: 730rpx;
  left: 50%;
  transform: translateX(-50%);
  border-radius: 1000rpx;
  background-color: #fff;
  bottom: 32rpx;
  .rank {
    width: 60rpx;
    height: 60rpx;
    border-radius: 50%;
    background: #9c94ff;
