    color: #fff;
    font-size: 34rpx;
    font-weight: bold;
    margin: 0 30rpx 0 50rpx;
    display: flex;
    justify-content: center;
    align-items: center;
  }
  .headImg {
    width: 72rpx;
    height: 72rpx;
    margin-right: 30rpx;
    img {
      width: 72rpx;
      height: 72rpx;
      border-radius: 50%;
    }
  }
  .ninckName {
    width: 200rpx;
    font-size: 28rpx;
    text-overflow: ellipsis;
    overflow: hidden;
    white-space: nowrap;
    color: #9c94ff;
    font-weight: bold;
    margin-right: 30rpx;
  }
  .paraghImg,
  .paraghImg img {
    width: 80rpx;
    height: 80rpx;
  }

  .paraghStar {
    font-weight: bold;
    .star {
      height: 40rpx;
      img {
        width: 24rpx;
        height: 24rpx;
      }
      span {
        color: #6760ba;
        font-size: 24rpx;
        margin-left: 5rpx;
      }
    }
    .paraghName {
      color: #6760ba;
      font-size: 24rpx;
      padding-top: 5rpx;
      margin-bottom: 10rpx;
    }
  }
}

.rank-spec {
  width: 306rpx;
  height: 100rpx;
  display: flex;
  flex-direction: column;
