    img {
      width: 24rpx;
      height: 30rpx;
    }
  }
}

.b-fight {
  display: flex;
  align-items: center;
  font-weight: bold;
  margin-left: 20rpx;
  .b-l {
    width: 3em;
    font-size: 28rpx;
